class Pizza:
    base_price = 10.0  # class variable

    def __init__(self, toppings, size="medium"):
        self.toppings = toppings  # instance variable
        self.size = size

    # Instance method -- accesses self (instance)
    def price(self):
        topping_cost = len(self.toppings) * 1.5
        size_multiplier = {"small": 0.8, "medium": 1.0, "large": 1.3}
        return (self.base_price + topping_cost) * size_multiplier[self.size]

    # Class method -- accesses cls (class), used as alternative constructor
    @classmethod
    def margherita(cls):
        """Factory method for a standard margherita."""
        return cls(["mozzarella", "tomato", "basil"], "medium")

    @classmethod
    def set_base_price(cls, price):
        """Modify class state."""
        cls.base_price = price

    # Static method -- no access to instance or class
    @staticmethod
    def validate_topping(topping):
        valid = {"mozzarella", "tomato", "basil", "pepperoni", "mushroom"}
        return topping.lower() in valid

# Instance method -- needs an instance
p = Pizza(["pepperoni", "mushroom"], "large")
print(p.price())  # (10.0 + 3.0) * 1.3 = 16.9

# Class method -- called on class or instance
m = Pizza.margherita()  # alternative constructor
print(m.toppings)  # ['mozzarella', 'tomato', 'basil']
print(type(m))     # <class 'Pizza'>

# Static method -- called on class or instance
print(Pizza.validate_topping("pepperoni"))  # True
print(p.validate_topping("pineapple"))      # False

