class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self._balance = balance  # private by convention
        self._transactions = []

    @property
    def balance(self):
        """Read-only computed from transactions."""
        return self._balance

    @balance.setter
    def balance(self, value):
        if value < 0:
            raise ValueError("Balance cannot be negative")
        self._balance = value

    @property
    def is_overdrawn(self):
        """Computed property -- no setter means read-only."""
        return self._balance < 0

    def deposit(self, amount):
        if amount <= 0:
            raise ValueError("Deposit must be positive")
        self._balance += amount
        self._transactions.append(("deposit", amount))

    def withdraw(self, amount):
        if amount > self._balance:
            raise ValueError("Insufficient funds")
        self._balance -= amount
        self._transactions.append(("withdraw", amount))

account = BankAccount("Alice", 1000)
print(account.balance)      # 1000 -- calls getter
account.deposit(500)
print(account.balance)      # 1500
print(account.is_overdrawn) # False -- computed property

try:
    account.balance = -100  # calls setter, raises ValueError
except ValueError as e:
    print(e)  # Balance cannot be negative

try:
    account.is_overdrawn = True  # AttributeError -- no setter
except AttributeError as e:
    print(e)  # property 'is_overdrawn' ... has no setter

