from datetime import datetime

class Date:
    def __init__(self, year: int, month: int, day: int):
        self.year = year
        self.month = month
        self.day = day

    def __repr__(self):
        return f"Date({self.year}, {self.month}, {self.day})"

    @classmethod
    def from_string(cls, date_str: str):
        """Create from 'YYYY-MM-DD' string."""
        year, month, day = map(int, date_str.split("-"))
        return cls(year, month, day)

    @classmethod
    def from_timestamp(cls, ts: float):
        """Create from Unix timestamp."""
        dt = datetime.fromtimestamp(ts)
        return cls(dt.year, dt.month, dt.day)

    @classmethod
    def today(cls):
        """Create for current date."""
        dt = datetime.now()
        return cls(dt.year, dt.month, dt.day)

    @classmethod
    def from_dict(cls, data: dict):
        """Create from dictionary."""
        return cls(data["year"], data["month"], data["day"])

# Multiple ways to create the same object
d1 = Date(2024, 1, 15)
d2 = Date.from_string("2024-01-15")
d3 = Date.from_dict({"year": 2024, "month": 1, "day": 15})
d4 = Date.today()

print(d1)  # Date(2024, 1, 15)
print(d2)  # Date(2024, 1, 15)

