# Practical: deprecation proxy
class DeprecatedAttrs:
    _deprecated = {'old_name': 'new_name', 'legacy': 'modern'}

    def __init__(self):
        self.new_name = "value"
        self.modern = "updated"

    def __getattr__(self, name):
        if name in self._deprecated:
            import warnings
            new = self._deprecated[name]
            warnings.warn(f"{name} is deprecated, use {new}",
                          DeprecationWarning, stacklevel=2)
            return getattr(self, new)
        raise AttributeError(f"No attribute {name}")

obj = DeprecatedAttrs()
print(obj.new_name)   # "value" (normal access)
print(obj.old_name)   # DeprecationWarning + "value"

