# Automatic subclass registration (plugin pattern)
class Plugin:
    _registry = {}

    def __init_subclass__(cls, plugin_name=None, **kwargs):
        super().__init_subclass__(**kwargs)
        name = plugin_name or cls.__name__.lower()
        cls._registry[name] = cls
        cls.plugin_name = name

    @classmethod
    def get_plugin(cls, name):
        return cls._registry.get(name)

class JSONPlugin(Plugin, plugin_name="json"):
    def process(self, data):
        return f"Processing JSON: {data}"

class XMLPlugin(Plugin, plugin_name="xml"):
    def process(self, data):
        return f"Processing XML: {data}"

class CSVPlugin(Plugin):  # auto-named "csvplugin"
    def process(self, data):
        return f"Processing CSV: {data}"

print(Plugin._registry)
# {'json': <class 'JSONPlugin'>, 'xml': <class 'XMLPlugin'>, 'csvplugin': <class 'CSVPlugin'>}

plugin_cls = Plugin.get_plugin("json")
plugin = plugin_cls()
print(plugin.process('{"key": "value"}'))
# Processing JSON: {"key": "value"}

# Enforcing constraints on subclasses
class Serializable:
    def __init_subclass__(cls, **kwargs):
        super().__init_subclass__(**kwargs)
        if not hasattr(cls, 'serialize'):
            raise TypeError(f"{cls.__name__} must implement serialize()")
        if not hasattr(cls, 'deserialize'):
            raise TypeError(f"{cls.__name__} must implement deserialize()")

class UserData(Serializable):
    def serialize(self):
        return str(self.__dict__)

    @classmethod
    def deserialize(cls, data):
        return cls()

