from dataclasses import dataclass, field
from typing import List, Protocol

# Good: dataclass for data containers
@dataclass
class Address:
    street: str
    city: str
    state: str
    zip_code: str

# Good: composition over inheritance
@dataclass
class Employee:
    name: str
    email: str
    address: Address  # composition (has-a)
    skills: List[str] = field(default_factory=list)

    def __repr__(self):
        return f"Employee({self.name!r}, {self.email!r})"

# Good: Protocol for duck typing (structural subtyping)
class Sendable(Protocol):
    def send(self, message: str) -> bool: ...

class EmailSender:
    def send(self, message: str) -> bool:
        print(f"Email: {message}")
        return True

class SlackSender:
    def send(self, message: str) -> bool:
        print(f"Slack: {message}")
        return True

def notify(sender: Sendable, msg: str) -> bool:
    return sender.send(msg)  # works with any object that has send()

# Good: small, focused classes with clear responsibilities
class PasswordValidator:
    def __init__(self, min_length: int = 8):
        self.min_length = min_length

    def validate(self, password: str) -> List[str]:
        errors = []
        if len(password) < self.min_length:
            errors.append(f"Must be at least {self.min_length} characters")
        if not any(c.isupper() for c in password):
            errors.append("Must contain an uppercase letter")
        if not any(c.isdigit() for c in password):
            errors.append("Must contain a digit")
        return errors

# Good: __slots__ for high-volume instances
class Point:
    __slots__ = ('x', 'y')

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def __repr__(self):
        return f"Point({self.x}, {self.y})"

